function FlagArt({ id }) {
  switch (id) {
    case "es": return (<><rect width="60" height="40" fill="#AA151B" /><rect y="10" width="60" height="20" fill="#F1BF00" /></>);
    case "it": return (<><rect width="20" height="40" fill="#009246" /><rect x="20" width="20" height="40" fill="#fff" /><rect x="40" width="20" height="40" fill="#CE2B37" /></>);
    case "gr": return (
      <>
        <rect width="60" height="40" fill="#fff" />
        {[0, 1, 2, 3].map((i) => <rect key={i} y={i * 8.9} width="60" height="4.45" fill="#0D5EAF" />)}
        <rect width="24" height="22.2" fill="#0D5EAF" />
        <rect x="9.5" width="5" height="22.2" fill="#fff" />
        <rect y="8.6" width="24" height="5" fill="#fff" />
      </>
    );
    case "fr": return (<><rect width="20" height="40" fill="#0055A4" /><rect x="20" width="20" height="40" fill="#fff" /><rect x="40" width="20" height="40" fill="#EF4135" /></>);
    case "hu": return (<><rect width="60" height="13.3" fill="#CD2A3E" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#436F4D" /></>);
    case "pl": return (<><rect width="60" height="20" fill="#fff" /><rect y="20" width="60" height="20" fill="#DC143C" /></>);
    case "de": return (<><rect width="60" height="13.3" fill="#000" /><rect y="13.3" width="60" height="13.3" fill="#DD0000" /><rect y="26.6" width="60" height="13.4" fill="#FFCE00" /></>);
    case "uk": return (
      <>
        <rect width="60" height="40" fill="#00247D" />
        <g stroke="#fff" strokeWidth="8"><line x1="0" y1="0" x2="60" y2="40" /><line x1="60" y1="0" x2="0" y2="40" /></g>
        <g stroke="#CF142B" strokeWidth="3"><line x1="0" y1="0" x2="60" y2="40" /><line x1="60" y1="0" x2="0" y2="40" /></g>
        <rect x="24" width="12" height="40" fill="#fff" /><rect y="14" width="60" height="12" fill="#fff" />
        <rect x="27" width="6" height="40" fill="#CF142B" /><rect y="17" width="60" height="6" fill="#CF142B" />
      </>
    );
    case "hr": return (<><rect width="60" height="13.3" fill="#FF0000" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#0093DD" /></>);
    case "cz": return (
      <>
        <rect width="60" height="20" fill="#fff" /><rect y="20" width="60" height="20" fill="#D7141A" />
        <polygon points="0,0 0,40 26,20" fill="#11457E" />
      </>
    );
    case "al": return (
      <>
        <rect width="60" height="40" fill="#E41E20" />
        <g fill="#111">
          <polygon points="8,15 24,20 8,25" /><polygon points="52,15 36,20 52,25" />
          <circle cx="24" cy="18" r="2.2" /><circle cx="36" cy="18" r="2.2" />
          <polygon points="26,21 30,26 34,21" />
        </g>
      </>
    );
    case "ma": return (
      <>
        <rect width="60" height="40" fill="#C1272D" />
        <polygon points="30,9 33.3,17.5 42.5,17.7 35.2,23.3 37.8,32.1 30,27 22.2,32.1 24.8,23.3 17.5,17.7 26.7,17.5"
          fill="none" stroke="#006233" strokeWidth="2" strokeLinejoin="round" />
      </>
    );
    case "at": return (<><rect width="60" height="13.3" fill="#ED2939" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#ED2939" /></>);
    case "be": return (<><rect width="20" height="40" fill="#000" /><rect x="20" width="20" height="40" fill="#FAE042" /><rect x="40" width="20" height="40" fill="#ED2939" /></>);
    case "cy": return (
      <>
        <rect width="60" height="40" fill="#fff" />
        <path d="M20 22c2-6 8-9 13-8 4 1 6 4 5 7-1 2-4 3-6 2 2 2 1 5-2 6-4 1-9-1-10-7Z" fill="#D57800" />
        <path d="M22 30c2 2 5 3 7 2M31 31c2 2 5 2 7 0" stroke="#4E7A33" strokeWidth="1.4" fill="none" strokeLinecap="round" />
      </>
    );
    case "dk": return (<><rect width="60" height="40" fill="#C8102E" /><rect x="22" width="6" height="40" fill="#fff" /><rect y="17" width="60" height="6" fill="#fff" /></>);
    case "ie": return (<><rect width="20" height="40" fill="#169B62" /><rect x="20" width="20" height="40" fill="#fff" /><rect x="40" width="20" height="40" fill="#FF883E" /></>);
    case "jo": return (
      <>
        <rect width="60" height="13.3" fill="#000" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#007A3D" />
        <polygon points="0,0 26,20 0,40" fill="#CE1126" />
        <polygon points="6,20 8.5,16.5 11,20 9.6,24.2 5.4,24.2" fill="#fff" />
      </>
    );
    case "mt": return (
      <>
        <rect width="30" height="40" fill="#fff" /><rect x="30" width="30" height="40" fill="#CF142B" />
        <rect x="2" y="2" width="12" height="12" fill="#fff" stroke="#8C8C8C" strokeWidth="1.2" />
        <rect x="4.5" y="4.5" width="7" height="7" fill="#CF142B" />
      </>
    );
    case "nl": return (<><rect width="60" height="13.3" fill="#AE1C28" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#21468B" /></>);
    case "eg": return (
      <>
        <rect width="60" height="13.3" fill="#CE1126" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#000" />
        <circle cx="30" cy="20" r="4" fill="#C09A3E" />
      </>
    );
    case "il": return (
      <>
        <rect width="60" height="40" fill="#fff" />
        <rect y="5" width="60" height="4" fill="#0038B8" /><rect y="31" width="60" height="4" fill="#0038B8" />
        <polygon points="30,15 33,21 39,21 34,25 36,31 30,27 24,31 26,25 21,21 27,21" fill="none" stroke="#0038B8" strokeWidth="1.6" />
      </>
    );
    case "md": return (
      <>
        <rect width="20" height="40" fill="#003DA5" /><rect x="20" width="20" height="40" fill="#FFD200" /><rect x="40" width="20" height="40" fill="#CE1126" />
        <circle cx="30" cy="20" r="5" fill="#C09A3E" stroke="#003DA5" strokeWidth="1" />
      </>
    );
    case "ae": return (
      <>
        <rect width="60" height="13.3" fill="#00732F" /><rect y="13.3" width="60" height="13.3" fill="#fff" /><rect y="26.6" width="60" height="13.4" fill="#000" />
        <rect width="16" height="40" fill="#CE1126" />
      </>
    );
    case "ch": return (
      <>
        <rect width="60" height="40" fill="#D52B1E" />
        <rect x="26" y="10" width="8" height="20" fill="#fff" /><rect x="18" y="18" width="24" height="8" fill="#fff" />
      </>
    );
    case "sk": return (
      <>
        <rect width="60" height="13.3" fill="#fff" /><rect y="13.3" width="60" height="13.3" fill="#0B4EA2" /><rect y="26.6" width="60" height="13.4" fill="#EE1C25" />
        <rect x="8" y="12" width="14" height="18" fill="#fff" stroke="#0B4EA2" strokeWidth="1" />
        <rect x="10" y="14" width="10" height="6" fill="#0B4EA2" /><rect x="10" y="21" width="10" height="7" fill="#EE1C25" />
      </>
    );
    case "lt": return (<><rect width="60" height="13.3" fill="#FDB913" /><rect y="13.3" width="60" height="13.3" fill="#006A44" /><rect y="26.6" width="60" height="13.4" fill="#C1272D" /></>);
    default: return <rect width="60" height="40" fill={PALETTE.ocean} />;
  }
}

function FlagBadge({ id, style, preserveAspectRatio = "xMidYMid meet" }) {
  return (
    <svg viewBox="0 0 60 40" preserveAspectRatio={preserveAspectRatio} style={{ display: "block", ...style }}>
      <FlagArt id={id} />
    </svg>
  );
}

