function emailSectionHtml(title, rows) {
  const rowsHtml = rows
    .filter((r) => r && r[1])
    .map(
      ([label, value]) =>
        `<tr><td style="padding:3px 0;color:#8E99AE;vertical-align:top;white-space:nowrap;padding-right:14px;">${label}</td><td style="padding:3px 0;color:#EEF1F6;font-weight:600;">${value}</td></tr>`
    )
    .join("");
  return `
    <div style="background:rgba(255,255,255,0.03);border:1px solid #232b3d;border-radius:12px;padding:14px 16px;margin-bottom:14px;">
      <div style="font-size:10.5px;letter-spacing:1px;text-transform:uppercase;color:#5C6579;font-weight:700;margin-bottom:8px;">${title}</div>
      <table style="width:100%;border-collapse:collapse;font-size:13px;">${rowsHtml}</table>
    </div>`;
}

async function sendTransactionalEmail({ to, subject, html, replyTo }) {
  try {
    const res = await fetch("/api/send-email", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ to, subject, html, replyTo }),
    });
    return res.ok;
  } catch {
    return false;
  }
}

/* ─────────────────────────────────────────────────────────────────────
   MOTION SYSTEM — една easing крива навсякъде, бавни луксозни преходи,
   hover = мек gold glow + леко повдигане. Прилага се чрез className
   (виж <style> в долния компонент) вместо inline transition навсякъде.
   ───────────────────────────────────────────────────────────────────── */

function StepDots({ step }) {
  const labels = ["Излитане", "Държава", "Град", "Запитване", "Преглед"];
  return (
    <div style={{ display: "flex", justifyContent: "center", gap: 8, padding: "20px 0 10px" }}>
      {labels.map((l, i) => (
        <div key={l} style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <div style={{
            width: 27, height: 27, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center",
            background: i <= step ? PALETTE.gold : "transparent",
            border: `1.5px solid ${i <= step ? PALETTE.gold : PALETTE.panelBorder}`,
            color: i <= step ? PALETTE.bgDeep : PALETTE.inkFaint, fontFamily: "Work Sans, sans-serif", fontWeight: 700, fontSize: 12,
            transition: "all .5s var(--ease)",
            boxShadow: i <= step ? "0 0 14px rgba(212,175,55,0.45)" : "none",
          }}>
            {i + 1}
          </div>
          {i < labels.length - 1 && <div style={{ width: 26, height: 1.5, background: i < step ? PALETTE.gold : PALETTE.panelBorder, transition: "background .5s var(--ease)" }} />}
        </div>
      ))}
    </div>
  );
}

