/* ─────────────────────────────────────────────────────────────────────
   ЗАБЕЛЕЖИТЕЛНОСТИ ЗА ОФЕРТИ — тук няма достъп до външни снимки (артефактната
   среда блокира зареждане на снимки от други домейни), затова най-известната
   забележителност на всеки град се рисува като елегантна векторна линия-арт
   илюстрация, разпозната по името на града. За градове без разпозната
   забележителност се показва обобщена илюстрация с ориентир/компас.
   ───────────────────────────────────────────────────────────────────── */
const LANDMARK_MATCHERS = [
  { key: "париж", id: "eiffel" },
  { key: "рим", id: "colosseum" },
  { key: "барселона", id: "sagrada" },
  { key: "лондон", id: "bigben" },
  { key: "атина", id: "parthenon" },
  { key: "прага", id: "prague" },
  { key: "виена", id: "ferris" },
  { key: "будапеща", id: "parliament" },
  { key: "берлин", id: "brandenburg" },
  { key: "дъблин", id: "bridge" },
  { key: "венеция", id: "gondola" },
  { key: "амстердам", id: "canal" },
];

function findLandmark(city) {
  const c = (city || "").trim().toLowerCase();
  if (!c) return "generic";
  const match = LANDMARK_MATCHERS.find((m) => c.includes(m.key));
  return match ? match.id : "generic";
}

