function TripTimeline({ hasInquiry, hasPayment, paid }) {
  const steps = [
    { label: "Запитване прието", done: hasInquiry },
    { label: "Оферта се подготвя", done: hasInquiry },
    { label: "Оферта готова за плащане", done: hasPayment },
    { label: "Платено", done: paid },
    { label: "Пътуване", done: paid },
  ];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
      {steps.map((s, i) => (
        <div key={i} style={{ display: "flex", gap: 12, alignItems: "flex-start" }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
            <div style={{
              width: 20, height: 20, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center",
              background: s.done ? PALETTE.gold : "transparent", border: `1.5px solid ${s.done ? PALETTE.gold : PALETTE.panelBorder}`,
              color: s.done ? PALETTE.bgDeep : PALETTE.inkFaint, flexShrink: 0,
            }}>
              {s.done ? <Check size={12} /> : null}
            </div>
            {i < steps.length - 1 && <div style={{ width: 1.5, flex: 1, minHeight: 22, background: steps[i + 1].done ? PALETTE.gold : PALETTE.panelBorder }} />}
          </div>
          <div style={{ fontSize: 13, color: s.done ? PALETTE.ink : PALETTE.inkFaint, fontWeight: s.done ? 600 : 400, paddingBottom: 18 }}>{s.label}</div>
        </div>
      ))}
    </div>
  );
}

